import { createSlice, PayloadAction } from '@reduxjs/toolkit';

export type AutosaveState = {
  enabled: boolean;
  lastSavedAt?: string;
};

const initialState: AutosaveState = {
  enabled: true,
};

const autosaveSlice = createSlice({
  name: 'autosave',
  initialState,
  reducers: {
    setEnabled(state, action: PayloadAction<boolean>) {
      state.enabled = action.payload;
    },
    setLastSavedAt(state, action: PayloadAction<string | undefined>) {
      state.lastSavedAt = action.payload;
    },
  },
});

export const { setEnabled, setLastSavedAt } = autosaveSlice.actions;
export default autosaveSlice.reducer;
