import React from 'react';
import AppBar from '@mui/material/AppBar';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Container from '@mui/material/Container';
import CircularProgress from '@mui/material/CircularProgress';
import Stack from '@mui/material/Stack';
import Toolbar from '@mui/material/Toolbar';
import Typography from '@mui/material/Typography';
import { Link, Route, Routes } from 'react-router-dom';

import AppSnackbar from './components/common/AppSnackbar';
import { useAppDispatch, useAppSelector } from './store/hooks';
import { hideSnackbar } from './store/slices/uiSlice';

const Dashboard = React.lazy(() => import('./pages/Dashboard'));
const ArticlesList = React.lazy(() => import('./pages/ArticlesList'));
const ArticleEditor = React.lazy(() => import('./pages/ArticleEditor'));
const CategoriesList = React.lazy(() => import('./pages/CategoriesList'));
const ImportArticles = React.lazy(() => import('./pages/ImportArticles'));
const NetworksList = React.lazy(() => import('./pages/NetworksList'));
const NotificationsList = React.lazy(() => import('./pages/NotificationsList'));

function App() {
  const dispatch = useAppDispatch();
  const snackbar = useAppSelector((s) => s.ui.snackbar);

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: '#f6f7fb' }}>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" sx={{ flexGrow: 1 }}>
            Taram
          </Typography>
          <Stack direction="row" spacing={1} sx={{ flexWrap: 'wrap', justifyContent: 'flex-end' }}>
            <Button aria-label="Dashboard" color="inherit" component={Link} to="/">
              Dashboard
            </Button>
            <Button aria-label="Articles" color="inherit" component={Link} to="/articles">
              Articles
            </Button>
            <Button aria-label="Importer des articles" color="inherit" component={Link} to="/import/articles">
              Import
            </Button>
            <Button aria-label="Categories" color="inherit" component={Link} to="/categories">
              Categories
            </Button>
            <Button aria-label="Networks" color="inherit" component={Link} to="/networks">
              Networks
            </Button>
            <Button aria-label="Notifications" color="inherit" component={Link} to="/notifications">
              Notifications
            </Button>
          </Stack>
        </Toolbar>
      </AppBar>

      <Container maxWidth="lg">
        <React.Suspense
          fallback={
            <Box sx={{ py: 6, display: 'flex', justifyContent: 'center' }}>
              <CircularProgress />
            </Box>
          }
        >
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/articles" element={<ArticlesList />} />
            <Route path="/articles/new" element={<ArticleEditor mode="create" />} />
            <Route path="/articles/:id/edit" element={<ArticleEditor mode="edit" />} />
            <Route path="/categories" element={<CategoriesList />} />
            <Route path="/import/articles" element={<ImportArticles />} />
            <Route path="/networks" element={<NetworksList />} />
            <Route path="/notifications" element={<NotificationsList />} />
          </Routes>
        </React.Suspense>
      </Container>

      <AppSnackbar state={snackbar} onClose={() => dispatch(hideSnackbar())} />
    </Box>
  );
}

export default App;
