import { createSlice, PayloadAction } from '@reduxjs/toolkit';

export type FiltersState = {
  query: string;
  categoryIds: number[];
  featured?: boolean;
  status?: 'draft' | 'published' | 'archived';
  networkId?: number;
};

const initialState: FiltersState = {
  query: '',
  categoryIds: [],
};

const filtersSlice = createSlice({
  name: 'filters',
  initialState,
  reducers: {
    setQuery(state, action: PayloadAction<string>) {
      state.query = action.payload;
    },
    setCategoryIds(state, action: PayloadAction<number[]>) {
      state.categoryIds = action.payload;
    },
    setFeatured(state, action: PayloadAction<boolean | undefined>) {
      state.featured = action.payload;
    },
    setStatus(state, action: PayloadAction<'draft' | 'published' | 'archived' | undefined>) {
      state.status = action.payload;
    },
    setNetworkId(state, action: PayloadAction<number | undefined>) {
      state.networkId = action.payload;
    },
    resetFilters() {
      return initialState;
    },
  },
});

export const { setQuery, setCategoryIds, setFeatured, setStatus, setNetworkId, resetFilters } = filtersSlice.actions;
export default filtersSlice.reducer;
