import React from 'react';
import Snackbar from '@mui/material/Snackbar';
import Alert from '@mui/material/Alert';

export type SnackbarState = {
  open: boolean;
  message: string;
  severity?: 'success' | 'info' | 'warning' | 'error';
};

type Props = {
  state: SnackbarState;
  onClose: () => void;
};

export default function AppSnackbar({ state, onClose }: Props) {
  return (
    <Snackbar open={state.open} autoHideDuration={4000} onClose={onClose} anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}>
      <Alert onClose={onClose} severity={state.severity ?? 'info'} sx={{ width: '100%' }} variant="filled">
        {state.message}
      </Alert>
    </Snackbar>
  );
}
